from dataclasses import dataclass, field
from enum import Enum
from typing import List, Optional


class GuildMemberRole(Enum):
    CORE      = "core"      # Guild co-owner; owns standards and artefacts
    EMBEDDED  = "embedded"  # Team liaison; attends forums, propagates patterns
    GUEST     = "guest"     # Ad-hoc attendee; no standing membership obligations


@dataclass
class GuildMember:
    member_id: str
    name: str
    role: GuildMemberRole
    home_team: str
    specialisation: str    # e.g. "eval frameworks", "prompt engineering", "ops"
    joined_date: str       # ISO-8601
    active: bool = True
    # Embedded members have a rotation period
    rotation_end_date: Optional[str] = None  # ISO-8601; None = permanent

    def time_commitment_hrs_per_week(self) -> float:
        """Expected guild time commitment by role."""
        commitments = {
            GuildMemberRole.CORE:     4.0,   # Forum facilitation + artefact maintenance
            GuildMemberRole.EMBEDDED: 1.5,   # Forum attendance + propagation in home team
            GuildMemberRole.GUEST:    0.0,   # No standing commitment
        }
        return commitments[self.role]

    def member_summary(self) -> str:
        rotation = f" (rotation ends {self.rotation_end_date})" if self.rotation_end_date else ""
        return (
            f"{self.name} | {self.role.value} | {self.home_team} "
            f"| {self.specialisation}{rotation}"
        )


@dataclass
class Guild:
    name: str
    charter_url: str
    members: List[GuildMember] = field(default_factory=list)

    def core_members(self) -> List[GuildMember]:
        return [m for m in self.members if m.role == GuildMemberRole.CORE and m.active]

    def embedded_members(self) -> List[GuildMember]:
        return [m for m in self.members if m.role == GuildMemberRole.EMBEDDED and m.active]

    def teams_represented(self) -> List[str]:
        return list({m.home_team for m in self.members if m.active})

    def roster_summary(self) -> str:
        core = self.core_members()
        embedded = self.embedded_members()
        teams = self.teams_represented()
        return (
            f"Guild: {self.name}\n"
            f"  Core members: {len(core)}\n"
            f"  Embedded members: {len(embedded)}\n"
            f"  Teams represented: {len(teams)} ({', '.join(teams)})\n"
            f"  Total weekly commitment: "
            f"{sum(m.time_commitment_hrs_per_week() for m in core + embedded):.1f}h"
        )

from dataclasses import dataclass, field
from enum import Enum
from typing import List, Optional
import datetime


class ArtefactType(Enum):
    PROMPT_PATTERN    = "prompt_pattern"      # Reusable prompt template with notes
    EVAL_STANDARD     = "eval_standard"       # Shared evaluation methodology
    ARCHITECTURE_ADR  = "architecture_adr"   # Cross-team architecture decision record
    POLICY            = "policy"             # Organisation-wide policy (PII, rate limits)
    INCIDENT_ENTRY    = "incident_entry"     # Learnings from a cross-team incident
    GUIDE             = "guide"              # How-to documentation


@dataclass
class GuildArtefact:
    artefact_id: str
    artefact_type: ArtefactType
    title: str
    description: str
    source_forum: str      # Forum session that produced this artefact
    owner: str             # Core member who maintains this artefact
    created_date: str      # ISO-8601
    last_reviewed_date: str
    review_cadence_days: int = 90
    adopted_by_teams: List[str] = field(default_factory=list)
    deprecated: bool = False
    deprecated_by: Optional[str] = None  # artefact_id of replacement

    def is_stale(self) -> bool:
        last = datetime.date.fromisoformat(self.last_reviewed_date)
        return (
            not self.deprecated
            and (datetime.date.today() - last).days > self.review_cadence_days
        )

    def adoption_rate(self, total_teams: int) -> float:
        return len(self.adopted_by_teams) / total_teams if total_teams > 0 else 0.0

    def artefact_summary(self, total_teams: int) -> str:
        status = "DEPRECATED" if self.deprecated else ("STALE" if self.is_stale() else "CURRENT")
        return (
            f"[{self.artefact_id}] {self.artefact_type.value} | {status}\n"
            f"  Title: {self.title}\n"
            f"  Owner: {self.owner} | Last reviewed: {self.last_reviewed_date}\n"
            f"  Adopted by: {len(self.adopted_by_teams)}/{total_teams} teams "
            f"({self.adoption_rate(total_teams):.0%})"
        )


class GuildArtefactLibrary:
    def __init__(self, total_teams: int) -> None:
        self._artefacts: dict = {}
        self._total_teams = total_teams

    def add(self, artefact: GuildArtefact) -> None:
        self._artefacts[artefact.artefact_id] = artefact

    def stale_artefacts(self) -> List[GuildArtefact]:
        return [a for a in self._artefacts.values() if a.is_stale()]

    def by_type(self, artefact_type: ArtefactType) -> List[GuildArtefact]:
        return [
            a for a in self._artefacts.values()
            if a.artefact_type == artefact_type and not a.deprecated
        ]

    def low_adoption(self, threshold: float = 0.5) -> List[GuildArtefact]:
        """Artefacts adopted by fewer than threshold fraction of teams."""
        return [
            a for a in self._artefacts.values()
            if not a.deprecated
            and a.adoption_rate(self._total_teams) < threshold
        ]

    def library_health(self) -> str:
        total = len(self._artefacts)
        stale = len(self.stale_artefacts())
        low = len(self.low_adoption())
        return (
            f"Guild Artefact Library: {total} artefacts\n"
            f"  Stale (overdue review): {stale}\n"
            f"  Low adoption (< 50% of teams): {low}"
        )

from dataclasses import dataclass, field
from typing import Dict, List


@dataclass
class GuildEffectivenessReport:
    report_quarter: str
    total_teams: int
    # Outcome metrics
    eval_score_variance: float        # Lower is better; tracks convergence
    eval_score_variance_prev: float   # Previous quarter, for trend
    artefact_adoption_rate: float     # Fraction of teams using core artefacts
    duplicate_incident_patterns: int  # Incidents with same root cause seen before
    avg_time_to_pattern_days: float   # Days from discovery to guild library
    embedded_member_renewal_rate: float  # Fraction who renewed their rotation
    # Context
    new_artefacts_this_quarter: int
    forums_held: int
    monthly_digest_subscribers: int

    def variance_trend(self) -> str:
        if self.eval_score_variance < self.eval_score_variance_prev:
            return f"IMPROVING ({self.eval_score_variance:.3f} < {self.eval_score_variance_prev:.3f})"
        return f"DIVERGING ({self.eval_score_variance:.3f} > {self.eval_score_variance_prev:.3f})"

    def health_grade(self) -> str:
        score = 0
        if self.eval_score_variance < self.eval_score_variance_prev:
            score += 25
        if self.artefact_adoption_rate >= 0.7:
            score += 25
        if self.duplicate_incident_patterns == 0:
            score += 25
        if self.embedded_member_renewal_rate >= 0.8:
            score += 25
        grades = {100: "A", 75: "B", 50: "C", 25: "D", 0: "F"}
        return grades.get(score, "D")

    def effectiveness_report(self) -> str:
        return (
            f"Guild Effectiveness Report {self.report_quarter}\n"
            f"  Grade: {self.health_grade()}\n"
            f"  Eval score variance: {self.variance_trend()}\n"
            f"  Artefact adoption: {self.artefact_adoption_rate:.0%} of teams\n"
            f"  Duplicate incident patterns: {self.duplicate_incident_patterns}\n"
            f"  Avg time-to-pattern: {self.avg_time_to_pattern_days:.0f} days\n"
            f"  Embedded member renewal: {self.embedded_member_renewal_rate:.0%}\n"
            f"  Forums held: {self.forums_held} | New artefacts: {self.new_artefacts_this_quarter}"
        )
